{
  "mode": "method",
  "tests": [
    {
      "name": "fix_env_variable_typo",
      "input": {
        "env": {
          "M2M_AUTH_DOMAIN": "topcoder-dev.auth0.com",
          "M2M_AUTH_AUDIENCE": "https://m2m.topcoder-dev.com/",
          "M2M_AUTH_PROXY_SEREVR_URL": ""
        }
      },
      "output": {
        "M2M_AUTH_PROXY_SERVER_URL": ""
      },
      "notes": "Ensures the typo in the environment variable is corrected."
    },
    {
      "name": "remove_sensitive_token",
      "input": {
        "mockApi": {
          "token": "xxxx"
        }
      },
      "output": {
        "token": "Environment variable required"
      },
      "notes": "Validates that sensitive information is not hardcoded."
    },
    {
      "name": "check_data_type_consistency",
      "input": {
        "migration": {
          "opportunityId": "TEXT"
        }
      },
      "output": {
        "opportunityId": "VARCHAR(14)"
      },
      "notes": "Ensures that the data type for opportunityId matches the referenced table."
    },
    {
      "name": "validate_timestamp_format",
      "input": {
        "migration": {
          "createdAt": "TIMESTAMP(3)"
        }
      },
      "output": {
        "createdAt": "Valid format"
      },
      "notes": "Checks that the timestamp format is correctly defined."
    },
    {
      "name": "edge_case_empty_env_variable",
      "input": {
        "env": {
          "M2M_AUTH_PROXY_SERVER_URL": ""
        }
      },
      "output": {
        "error": "Proxy server URL cannot be empty"
      },
      "notes": "Tests handling of an empty environment variable."
    },
    {
      "name": "adversarial_case_invalid_token",
      "input": {
        "mockApi": {
          "token": "invalid_token"
        }
      },
      "output": {
        "error": "Invalid token"
      },
      "notes": "Tests the system's response to an invalid token."
    },
    {
      "name": "check_migration_sql_syntax",
      "input": {
        "migration": {
          "sql": "CREATE TABLE review_application (id VARCHAR(14), userId TEXT, handle TEXT, opportunityId TEXT)"
        }
      },
      "output": {
        "valid": true
      },
      "notes": "Validates the SQL syntax in migration files."
    },
    {
      "name": "ensure_no_hardcoded_tokens",
      "input": {
        "mockApi": {
          "token": "hardcoded_token"
        }
      },
      "output": {
        "error": "Token must be stored in environment variables"
      },
      "notes": "Ensures that no hardcoded tokens exist in the codebase."
    }
  ],
  "assumptions": "All tests assume the environment is set up correctly and the database schema is accessible.",
  "notes": "Tests focus on security, data integrity, and code quality improvements."
}
